/**
 * Player database.
 *
 * ~350 real footballers across positions, nationalities, leagues, eras and
 * ability tiers. Every entry has full attributes so questions become
 * meaningful (Ballon d'Or, WC, UCL, foot, style, playing metrics...).
 *
 * Compact tuple format keeps this file readable while producing full Player
 * objects at import time. Add players by appending tuples.
 *
 * Tier: icon (95-99) | elite (89-94) | great (85-88) | good (80-84) | pro (72-79)
 */

export type Position = "GK" | "DEF" | "MID" | "FWD";
export type Era = "classic" | "modern" | "current"; // <2000 / 2000-2015 / 2015+
export type Tier = "icon" | "elite" | "great" | "good" | "pro";
export type Foot = "left" | "right" | "both";

export interface Player {
  id: string;
  name: string;
  position: Position;
  nationality: string;
  clubs: string[];
  leagues: string[];      // "Premier League", "La Liga", etc.
  era: Era;
  active: boolean;         // true = still playing
  height: number;          // cm
  foot: Foot;
  style: string;
  rating: number;          // 72-99
  tier: Tier;
  // honours
  ballonDor: boolean;
  worldCup: boolean;
  championsLeague: boolean;
  leagueTitles: number;
  careerGoals: number;
  caps: number;            // international caps
  legendary: boolean;
  captain: boolean;
  // playing attributes (0-100)
  versatility: number;
  speed: number;
  physicality: number;
  passing: number;
  shooting: number;
  defending: number;
  dribbling: number;
  portraitUrl?: string;    // optional real portrait override
}

// ---------------------------------------------------------------- Helpers

type Extras = Partial<{
  bd: number; wc: boolean; cl: boolean; lt: number; g: number;
  c: number; leg: boolean; cap: boolean; h: number; ver: number;
  spd: number; phy: number; pas: number; sho: number; def: number;
  dri: number; portrait: string;
}>;

// [id, name, pos, nat, era, active, foot, rating, tier, clubs[], leagues[], extras]
type Row = [
  string, string, Position, string, Era, boolean, Foot,
  number, Tier, string[], string[], Extras
];

const TIER_BASE: Record<Tier, { spd: number; phy: number; pas: number; sho: number; def: number; dri: number }> = {
  icon:  { spd: 88, phy: 82, pas: 88, sho: 88, def: 78, dri: 90 },
  elite: { spd: 84, phy: 80, pas: 82, sho: 82, def: 76, dri: 84 },
  great: { spd: 80, phy: 78, pas: 78, sho: 78, def: 74, dri: 78 },
  good:  { spd: 76, phy: 74, pas: 74, sho: 72, def: 70, dri: 74 },
  pro:   { spd: 70, phy: 70, pas: 68, sho: 65, def: 66, dri: 68 },
};

function derive(pos: Position, tier: Tier, key: keyof typeof TIER_BASE.icon): number {
  const base = TIER_BASE[tier][key];
  // Positional bias
  const bias: Partial<Record<Position, Partial<Record<typeof key, number>>>> = {
    GK:  { spd: -20, dri: -25, sho: -35, pas: -5,  def: 5,   phy: 0 },
    DEF: { def: 10,  sho: -18, dri: -8,  pas: 0,   phy: 6,   spd: -2 },
    MID: { pas: 8,   dri: 4,   def: -4,  sho: -4,  phy: -2 },
    FWD: { sho: 10,  dri: 8,   spd: 6,   def: -18, phy: -2,  pas: -2 },
  };
  const b = bias[pos]?.[key] ?? 0;
  return Math.max(20, Math.min(99, base + b));
}

function toPlayer(r: Row): Player {
  const [id, name, pos, nat, era, active, foot, rating, tier, clubs, leagues, x] = r;
  return {
    id, name, position: pos, nationality: nat, clubs, leagues, era, active, foot,
    rating, tier,
    height: x.h ?? (pos === "GK" ? 190 : pos === "DEF" ? 184 : pos === "MID" ? 178 : 180),
    style: "",
    ballonDor: (x.bd ?? 0) > 0,
    worldCup: x.wc ?? false,
    championsLeague: x.cl ?? false,
    leagueTitles: x.lt ?? 0,
    careerGoals: x.g ?? 0,
    caps: x.c ?? 0,
    legendary: x.leg ?? (tier === "icon" || (tier === "elite" && (x.bd ?? 0) > 0)),
    captain: x.cap ?? false,
    versatility: x.ver ?? (pos === "MID" ? 78 : 68),
    speed:      x.spd ?? derive(pos, tier, "spd"),
    physicality:x.phy ?? derive(pos, tier, "phy"),
    passing:    x.pas ?? derive(pos, tier, "pas"),
    shooting:   x.sho ?? derive(pos, tier, "sho"),
    defending:  x.def ?? derive(pos, tier, "def"),
    dribbling:  x.dri ?? derive(pos, tier, "dri"),
    portraitUrl: x.portrait,
  };
}

