const ROWS: Row[] = [...GK, ...DEF, ...MID, ...FWD];
export const PLAYERS: readonly Player[] = ROWS.map(toPlayer);

export const PLAYERS_BY_POSITION: Record<Position, readonly Player[]> = {
  GK: PLAYERS.filter((p) => p.position === "GK"),
  DEF: PLAYERS.filter((p) => p.position === "DEF"),
  MID: PLAYERS.filter((p) => p.position === "MID"),
  FWD: PLAYERS.filter((p) => p.position === "FWD"),
};

// Continent inference (rough — enough for question deduction)
const AFRICAN = new Set(["Nigeria","Senegal","Ghana","Ivory Coast","Algeria","Morocco","Egypt","Cameroon","Mali","Guinea","South Africa","DR Congo","Tunisia"]);
const ASIAN   = new Set(["South Korea","Japan","Saudi Arabia","Iran","Qatar","Australia","China"]);
const NA      = new Set(["USA","Mexico","Canada","Costa Rica","Jamaica"]);
const SA_C    = new Set(["Brazil","Argentina","Uruguay","Colombia","Chile","Peru","Paraguay","Ecuador","Venezuela","Bolivia"]);

export function continentOf(nat: string): "Europe" | "Africa" | "Asia" | "N.America" | "S.America" | "Other" {
  if (AFRICAN.has(nat)) return "Africa";
  if (ASIAN.has(nat)) return "Asia";
  if (NA.has(nat)) return "N.America";
  if (SA_C.has(nat)) return "S.America";
  return "Europe";
}
